实现浮层的源码如下所示：

```javascript
createHighlightBox: function(step) {
    // 创建浮层容器
    var highlightBox = document.createElement('div');
    // 设置容器样式
    highlightBox.className = "driver-highlight";
    highlightBox.style.position = 'absolute';
    // 设置容器位置
    highlightBox.style.left = '0';
    highlightBox.style.top = '0';
    highlightBox.style.width = '100%';
    highlightBox.style.height = '100%';
    highlightBox.style.zIndex = this.options.zIndex + 1;
    // 创建透明背景遮罩层
    var backDrop = document.createElement('div');
    backDrop.className = 'driver-backdrop';
    backDrop.style.backgroundColor = this.options.overlayColor;
    highlightBox.appendChild(backDrop);

    // 创建浮层内容区域
    var highlightArea = document.createElement('div');
    highlightBox.appendChild(highlightArea);
    // 添加提示文本
    if (step.text) {
        var message = document.createElement('div');
        message.className = 'driver-message';
        message.innerHTML = step.text;
        highlightArea.appendChild(message);
    }
    // 添加关闭和下一步按钮
    var buttons = document.createElement('div');
    buttons.className = 'driver-buttons';
    highlightBox.appendChild(buttons);

    // 添加关闭按钮
    var closeButton = document.createElement('a');
    closeButton.className = 'driver-close';
    closeButton.href = '#';
    closeButton.innerHTML = step.closeBtnText || this.options.closeBtnText;
    buttons.appendChild(closeButton);

    // 添加下一步按钮
    if (step.nextBtnText !== false) {
        var nextButton = document.createElement('a');
        nextButton.className = 'driver-next';
        nextButton.href = '#';
        nextButton.innerHTML = step.nextBtnText || this.options.nextBtnText;
        buttons.appendChild(nextButton);
    }

    return highlightBox;
}
```

在这段代码中，`createHighlightBox`函数创建了浮层容器，并设置了其样式和位置。该函数先创建了一个`div`元素，并分别设置了其类名、位置、大小和层级。然后，函数创建了一个透明背景层，并将其添加到创建的`div`元素中。接下来，函数创建了一个浮层内容区域，并在其中添加了提示文本和关闭和下一步按钮。最后，函数将浮层容器返回。

此源码是Driver.js实现浮层的一部分，它可以创建定制的浮层来引导用户完成特定任务。

当使用Driver.js对一个元素进行突出显示时，它会创建一个具有背景遮罩和提示文本的新容器，使该元素突出显示。例如，下面是一个用于突出显示具有id属性为"example-element"的元素的示例代码：

```javascript
var exampleStep = {
    selector: '#example-element',
    text: '这是需要突出显示的元素',
    position: {
        top: 20,
        left: 20
    }
};
// 创建一个包含上面示例代码的步骤对象

var highlightBox = document.createElement('div');
highlightBox.className = 'driver-highlight';
highlightBox.style.position = 'absolute';
highlightBox.style.left = '0';
highlightBox.style.top = '0';
highlightBox.style.width = '100%';
highlightBox.style.height = '100%';
highlightBox.style.zIndex = 10000;

// 创建透明黑色背景层
var backDrop = document.createElement('div');
backDrop.className = 'driver-backdrop';
backDrop.style.backgroundColor = 'rgba(0,0,0,0.5)';

// 选择需要高亮显示的元素
var exampleElement = document.querySelector('#example-element');

// 设置浮层内容区域位置
var highlightArea = document.createElement('div');
highlightArea.style.position = 'absolute';
highlightArea.style.top = '50%';
highlightArea.style.left = '50%';
highlightArea.style.transform = 'translate(-50%, -50%)';

// 添加提示文本到浮层内容区域
var message = document.createElement('div');
message.className = 'driver-message';
message.innerHTML = exampleStep.text;
highlightArea.appendChild(message);

// 添加关闭和下一步按钮
var buttons = document.createElement('div');
buttons.className = 'driver-buttons';

// 添加关闭按钮
var closeButton = document.createElement('a');
closeButton.className = 'driver-close';
closeButton.href = '#';
closeButton.innerHTML = 'Close';
buttons.appendChild(closeButton);

// 添加下一步按钮
var nextButton = document.createElement('a');
nextButton.className = 'driver-next';
nextButton.href = '#';
nextButton.innerHTML = 'Next';
buttons.appendChild(nextButton);

// 将这三个元素添加到高亮元素周围的新容器中
highlightBox.appendChild(backDrop);
highlightBox.appendChild(highlightArea);
highlightBox.appendChild(buttons);
exampleElement.parentElement.appendChild(highlightBox);
```

在以上示例中，我们首先创建了一个`step`对象，其中将被高亮突出显示的元素的选择器设置为`#example-element`。然后，我们创建了一个新的浮层容器，并在其中添加了透明黑色背景层、提示文本和按钮。最后，所有这些元素都被添加到需要高亮显示的元素的父容器中，以使它们位于被突出显示的元素周围。

总之，当我们需要突出显示某个元素时，Driver.js将通过添加一个具有背景遮罩和提示文本的新容器来实现这一目的。此容器的位置、大小和样式均可通过CSS进行控制，使其与被强调元素完全对齐。
